using System;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class PaginatedListTests
    {
        [Fact]
        public void Create_ReturnsCorrectPageItems()
        {
            var source = Enumerable.Range(1, 50).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Equal(10, result.Count);
            Assert.Equal(1, result.First());
            Assert.Equal(10, result.Last());
        }

        [Fact]
        public void Create_SecondPage_ReturnsCorrectItems()
        {
            var source = Enumerable.Range(1, 50).AsQueryable();

            var result = PaginatedList<int>.Create(source, 2, 10);

            Assert.Equal(10, result.Count);
            Assert.Equal(11, result.First());
            Assert.Equal(20, result.Last());
        }

        [Fact]
        public void Create_SetsCorrectPageIndex()
        {
            var source = Enumerable.Range(1, 50).AsQueryable();

            var result = PaginatedList<int>.Create(source, 3, 10);

            Assert.Equal(3, result.PageIndex);
        }

        [Fact]
        public void Create_CalculatesTotalPages()
        {
            var source = Enumerable.Range(1, 50).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Equal(5, result.TotalPages);
        }

        [Fact]
        public void Create_PartialLastPage_RoundsUpTotalPages()
        {
            var source = Enumerable.Range(1, 51).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Equal(6, result.TotalPages);
        }

        [Fact]
        public void HasPreviousPage_FirstPage_ReturnsFalse()
        {
            var source = Enumerable.Range(1, 50).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.False(result.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_SecondPage_ReturnsTrue()
        {
            var source = Enumerable.Range(1, 50).AsQueryable();

            var result = PaginatedList<int>.Create(source, 2, 10);

            Assert.True(result.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_LastPage_ReturnsFalse()
        {
            var source = Enumerable.Range(1, 50).AsQueryable();

            var result = PaginatedList<int>.Create(source, 5, 10);

            Assert.False(result.HasNextPage);
        }

        [Fact]
        public void HasNextPage_NotLastPage_ReturnsTrue()
        {
            var source = Enumerable.Range(1, 50).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.True(result.HasNextPage);
        }

        [Fact]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            var source = Enumerable.Empty<int>().AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Empty(result);
            Assert.Equal(1, result.PageIndex);
            Assert.Equal(0, result.TotalPages);
        }

        [Fact]
        public void Create_SingleItem_SinglePage()
        {
            var source = new[] { 42 }.AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Single(result);
            Assert.Equal(42, result[0]);
            Assert.Equal(1, result.TotalPages);
            Assert.False(result.HasPreviousPage);
            Assert.False(result.HasNextPage);
        }

        [Fact]
        public void Constructor_SetsPropertiesCorrectly()
        {
            var items = new[] { 1, 2, 3 }.ToList();

            var list = new PaginatedList<int>(items, 25, 2, 10);

            Assert.Equal(2, list.PageIndex);
            Assert.Equal(3, list.TotalPages);
            Assert.Equal(3, list.Count);
        }

        [Fact]
        public void Create_LastPageWithFewerItems()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(source, 3, 10);

            Assert.Equal(5, result.Count);
            Assert.Equal(21, result.First());
            Assert.Equal(25, result.Last());
        }
    }
}

using System;
using ContosoUniversity.Models;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class ModelTests
    {
        [Fact]
        public void Person_FullName_ReturnsLastNameCommaFirst()
        {
            var student = new Student { FirstMidName = "Carson", LastName = "Alexander" };

            Assert.Equal("Alexander, Carson", student.FullName);
        }

        [Fact]
        public void Person_FullName_InstructorWorks()
        {
            var instructor = new Instructor
            {
                FirstMidName = "Kim",
                LastName = "Abercrombie",
                HireDate = DateTime.Parse("1995-03-11")
            };

            Assert.Equal("Abercrombie, Kim", instructor.FullName);
        }

        [Fact]
        public void ErrorViewModel_ShowRequestId_WithId_ReturnsTrue()
        {
            var model = new ErrorViewModel { RequestId = "abc123" };

            Assert.True(model.ShowRequestId);
        }

        [Fact]
        public void ErrorViewModel_ShowRequestId_WithEmpty_ReturnsFalse()
        {
            var model = new ErrorViewModel { RequestId = "" };

            Assert.False(model.ShowRequestId);
        }

        [Fact]
        public void ErrorViewModel_ShowRequestId_WithNull_ReturnsFalse()
        {
            var model = new ErrorViewModel { RequestId = null };

            Assert.False(model.ShowRequestId);
        }

        [Fact]
        public void Student_InheritsFromPerson()
        {
            var student = new Student();
            Assert.IsAssignableFrom<Person>(student);
        }

        [Fact]
        public void Instructor_InheritsFromPerson()
        {
            var instructor = new Instructor();
            Assert.IsAssignableFrom<Person>(instructor);
        }

        [Fact]
        public void Course_Properties_SetCorrectly()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1,
                TeachingMaterialImagePath = "/images/chem.jpg"
            };

            Assert.Equal(1050, course.CourseID);
            Assert.Equal("Chemistry", course.Title);
            Assert.Equal(3, course.Credits);
            Assert.Equal(1, course.DepartmentID);
            Assert.Equal("/images/chem.jpg", course.TeachingMaterialImagePath);
        }

        [Fact]
        public void Department_Properties_SetCorrectly()
        {
            var dept = new Department
            {
                DepartmentID = 1,
                Name = "English",
                Budget = 350000m,
                StartDate = DateTime.Parse("2007-09-01"),
                InstructorID = 5
            };

            Assert.Equal(1, dept.DepartmentID);
            Assert.Equal("English", dept.Name);
            Assert.Equal(350000m, dept.Budget);
            Assert.Equal(5, dept.InstructorID);
        }

        [Fact]
        public void Department_InstructorID_Nullable()
        {
            var dept = new Department { DepartmentID = 1, Name = "Test" };
            Assert.Null(dept.InstructorID);
        }

        [Fact]
        public void Enrollment_Grade_Nullable()
        {
            var enrollment = new Enrollment
            {
                EnrollmentID = 1,
                CourseID = 1050,
                StudentID = 1
            };

            Assert.Null(enrollment.Grade);
        }

        [Fact]
        public void Enrollment_AllGradeValues()
        {
