using System;
using ContosoUniversity.Models;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class ModelTests
    {
        [Fact]
        public void Person_FullName_ReturnsLastNameCommaFirst()
        {
            var student = new Student { FirstMidName = "Carson", LastName = "Alexander" };

            Assert.Equal("Alexander, Carson", student.FullName);
        }

        [Fact]
        public void Person_FullName_InstructorWorks()
        {
            var instructor = new Instructor
            {
                FirstMidName = "Kim",
                LastName = "Abercrombie",
                HireDate = DateTime.Parse("1995-03-11")
            };

            Assert.Equal("Abercrombie, Kim", instructor.FullName);
        }

        [Fact]
        public void ErrorViewModel_ShowRequestId_WithId_ReturnsTrue()
        {
            var model = new ErrorViewModel { RequestId = "abc123" };

            Assert.True(model.ShowRequestId);
        }

        [Fact]
        public void ErrorViewModel_ShowRequestId_WithEmpty_ReturnsFalse()
        {
            var model = new ErrorViewModel { RequestId = "" };

            Assert.False(model.ShowRequestId);
        }

        [Fact]
        public void ErrorViewModel_ShowRequestId_WithNull_ReturnsFalse()
        {
            var model = new ErrorViewModel { RequestId = null };

            Assert.False(model.ShowRequestId);
        }

        [Fact]
        public void Student_InheritsFromPerson()
        {
            var student = new Student();
            Assert.IsAssignableFrom<Person>(student);
        }

        [Fact]
        public void Instructor_InheritsFromPerson()
        {
            var instructor = new Instructor();
            Assert.IsAssignableFrom<Person>(instructor);
        }

        [Fact]
        public void Course_Properties_SetCorrectly()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1,
                TeachingMaterialImagePath = "/images/chem.jpg"
            };

            Assert.Equal(1050, course.CourseID);
            Assert.Equal("Chemistry", course.Title);
            Assert.Equal(3, course.Credits);
            Assert.Equal(1, course.DepartmentID);
            Assert.Equal("/images/chem.jpg", course.TeachingMaterialImagePath);
        }

        [Fact]
        public void Department_Properties_SetCorrectly()
        {
            var dept = new Department
            {
                DepartmentID = 1,
                Name = "English",
                Budget = 350000m,
                StartDate = DateTime.Parse("2007-09-01"),
                InstructorID = 5
            };

            Assert.Equal(1, dept.DepartmentID);
            Assert.Equal("English", dept.Name);
            Assert.Equal(350000m, dept.Budget);
            Assert.Equal(5, dept.InstructorID);
        }

        [Fact]
        public void Department_InstructorID_Nullable()
        {
            var dept = new Department { DepartmentID = 1, Name = "Test" };
            Assert.Null(dept.InstructorID);
        }

        [Fact]
        public void Enrollment_Grade_Nullable()
        {
            var enrollment = new Enrollment
            {
                EnrollmentID = 1,
                CourseID = 1050,
                StudentID = 1
            };

            Assert.Null(enrollment.Grade);
        }

        [Fact]
        public void Enrollment_AllGradeValues()
        {
            Assert.Equal(0, (int)Grade.A);
            Assert.Equal(1, (int)Grade.B);
            Assert.Equal(2, (int)Grade.C);
            Assert.Equal(3, (int)Grade.D);
            Assert.Equal(4, (int)Grade.F);
        }

        [Fact]
        public void Notification_Properties_SetCorrectly()
        {
            var now = DateTime.Now;
            var notification = new Notification
            {
                Id = 1,
                EntityType = "Student",
                EntityId = "42",
                Operation = "CREATE",
                Message = "New Student created",
                CreatedAt = now,
                CreatedBy = "admin",
                IsRead = false,
                ReadAt = null
            };

            Assert.Equal(1, notification.Id);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("42", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Equal("New Student created", notification.Message);
            Assert.Equal(now, notification.CreatedAt);
            Assert.Equal("admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
            Assert.Null(notification.ReadAt);
        }

        [Fact]
        public void EntityOperation_Values()
        {
            Assert.Equal(0, (int)EntityOperation.CREATE);
            Assert.Equal(1, (int)EntityOperation.UPDATE);
            Assert.Equal(2, (int)EntityOperation.DELETE);
        }

        [Fact]
        public void OfficeAssignment_Properties_SetCorrectly()
        {
            var office = new OfficeAssignment
            {
                InstructorID = 10,
                Location = "Smith 17"
            };

            Assert.Equal(10, office.InstructorID);
            Assert.Equal("Smith 17", office.Location);
        }

        [Fact]
        public void CourseAssignment_Properties_SetCorrectly()
        {
            var ca = new CourseAssignment
            {
                InstructorID = 10,
                CourseID = 1050
            };

            Assert.Equal(10, ca.InstructorID);
            Assert.Equal(1050, ca.CourseID);
        }

        [Fact]
        public void Student_EnrollmentDate_SetCorrectly()
        {
            var date = DateTime.Parse("2020-09-01");
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = date
            };

            Assert.Equal(date, student.EnrollmentDate);
        }

        [Fact]
        public void Instructor_HireDate_SetCorrectly()
        {
            var date = DateTime.Parse("2000-01-15");
            var instructor = new Instructor
            {
                FirstMidName = "Test",
                LastName = "Instructor",
                HireDate = date
            };

            Assert.Equal(date, instructor.HireDate);
        }
    }
}

