        public void Dispose()
        {
            TestHelpers.DrainNotificationQueue(_controller.notificationService);
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void GetNotifications_EmptyQueue_ReturnsEmptyList()
        {
            var result = _controller.GetNotifications();

            Assert.NotNull(result);
