        public void GetNotifications_WithNotifications_ReturnsNotifications()
        {
            // Send some notifications through the service
            _controller.notificationService.SendNotification("Student", "1", "John", EntityOperation.CREATE);
            _controller.notificationService.SendNotification("Course", "2", "Math", EntityOperation.UPDATE);

            var result = _controller.GetNotifications();

            Assert.NotNull(result);
            Assert.NotNull(result.Value);
        }

        [Fact]
        public void GetNotifications_LimitsTo10()
        {
            // Send more than 10 notifications
            for (int i = 0; i < 15; i++)
            {
                _controller.notificationService.SendNotification("Student", i.ToString(), EntityOperation.CREATE);
            }

            var result = _controller.GetNotifications();

            Assert.NotNull(result);
