using Moq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class HomeControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly HomeController _controller;

        public HomeControllerTests()
        {
            _context = TestHelpers.CreateContext();
            _controller = new HomeController(_context);
            _controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
            _controller.TempData = new TempDataDictionary(
                _controller.ControllerContext.HttpContext,
                Mock.Of<ITempDataProvider>());
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index();

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void About_ReturnsViewWithEnrollmentDateGroups()
        {
            // Seed students with different enrollment dates
            _context.Students.AddRange(
                new Student { FirstMidName = "A", LastName = "A", EnrollmentDate = DateTime.Parse("2020-09-01") },
                new Student { FirstMidName = "B", LastName = "B", EnrollmentDate = DateTime.Parse("2020-09-01") },
                new Student { FirstMidName = "C", LastName = "C", EnrollmentDate = DateTime.Parse("2021-09-01") }
            );
            _context.SaveChanges();

            var result = _controller.About() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<EnrollmentDateGroup>>(result.Model);
            Assert.Equal(2, model.Count);
            Assert.Contains(model, g => g.StudentCount == 2);
            Assert.Contains(model, g => g.StudentCount == 1);
        }

        [Fact]
        public void About_NoStudents_ReturnsEmptyList()
        {
            var result = _controller.About() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<EnrollmentDateGroup>>(result.Model);
            Assert.Empty(model);
        }

        [Fact]
        public void Contact_ReturnsViewWithMessage()
        {
            var result = _controller.Contact() as ViewResult;

            Assert.NotNull(result);
            Assert.Equal("Your contact page.", _controller.ViewBag.Message);
        }

        [Fact]
        public void Error_ReturnsViewResult()
        {
            var result = _controller.Error();

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Unauthorized_ReturnsViewWithMessage()
        {
            var result = _controller.Unauthorized() as ViewResult;

            Assert.NotNull(result);
            Assert.Equal("You don't have permission to access this resource.", _controller.ViewBag.Message);
        }
    }
}

