using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Net;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Microsoft.Extensions.Logging;
using Moq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly CoursesController _controller;
        private readonly Mock<IWebHostEnvironment> _mockEnv;
        private readonly Mock<ILogger<CoursesController>> _mockLogger;
        private readonly string _tempDir;

        public CoursesControllerTests()
        {
            _context = TestHelpers.CreateContext();
            _tempDir = Path.Combine(Path.GetTempPath(), "contoso_test_" + Guid.NewGuid().ToString("N"));
            Directory.CreateDirectory(_tempDir);

            _mockEnv = new Mock<IWebHostEnvironment>();
            _mockEnv.Setup(e => e.WebRootPath).Returns(_tempDir);
            _mockEnv.Setup(e => e.ContentRootPath).Returns(_tempDir);

            _mockLogger = new Mock<ILogger<CoursesController>>();

            _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
            _controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
            _controller.TempData = new TempDataDictionary(
                _controller.ControllerContext.HttpContext,
                Mock.Of<ITempDataProvider>());
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
            try { if (Directory.Exists(_tempDir)) Directory.Delete(_tempDir, true); } catch { }
        }

        #region Index

        [Fact]
        public void Index_ReturnsViewWithCourses()
        {
            TestHelpers.SeedCourses(_context);

            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<List<Course>>(result.Model);
            Assert.Equal(2, model.Count);
        }

        [Fact]
        public void Index_NoCourses_ReturnsEmptyList()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<List<Course>>(result.Model);
            Assert.Empty(model);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithCourse()
        {
            TestHelpers.SeedCourses(_context);

            var result = _controller.Details(1050) as ViewResult;

            Assert.NotNull(result);
            var course = Assert.IsType<Course>(result.Model);
            Assert.Equal("Chemistry", course.Title);
        }

        [Fact]
        public void Details_InvalidId_ThrowsInvalidOperationException()
        {
            // Single() throws when no match
            Assert.Throws<InvalidOperationException>(() => _controller.Details(9999));
        }

        #endregion

        #region Create GET

        [Fact]
        public void Create_GET_ReturnsViewWithCourse()
        {
            TestHelpers.SeedDepartments(_context);

            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            Assert.IsType<Course>(result.Model);
        }

        [Fact]
        public void Create_GET_SetsViewBagDepartmentID()
        {
            TestHelpers.SeedDepartments(_context);

            _controller.Create();

            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        #endregion

        #region Create POST

        [Fact]
        public void Create_POST_ValidModel_RedirectsToIndex()
        {
            TestHelpers.SeedDepartments(_context);
            var course = new Course
            {
                CourseID = 3000,
                Title = "New Course",
                Credits = 3,
                DepartmentID = 1
            };

            var result = _controller.Create(course, null) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Create_POST_ValidModel_SavesCourse()
        {
            TestHelpers.SeedDepartments(_context);
            var course = new Course
            {
                CourseID = 3000,
                Title = "New Course",
                Credits = 3,
                DepartmentID = 1
            };

            _controller.Create(course, null);

            Assert.NotNull(_context.Courses.Find(3000));
        }

        [Fact]
        public void Create_POST_InvalidModelState_ReturnsView()
        {
            TestHelpers.SeedDepartments(_context);
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 3000, DepartmentID = 1 };

            var result = _controller.Create(course, null) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Create_POST_WithValidImage_SavesFilePath()
        {
            TestHelpers.SeedDepartments(_context);
            var course = new Course
            {
                CourseID = 3000,
                Title = "New Course",
                Credits = 3,
                DepartmentID = 1
            };

            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns("test.jpg");
            mockFile.Setup(f => f.Length).Returns(1024);
            mockFile.Setup(f => f.CopyTo(It.IsAny<Stream>()));

            var result = _controller.Create(course, mockFile.Object) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            var saved = _context.Courses.Find(3000);
            Assert.NotNull(saved.TeachingMaterialImagePath);
            Assert.Contains("/Uploads/TeachingMaterials/", saved.TeachingMaterialImagePath);
        }

        [Fact]
        public void Create_POST_InvalidFileExtension_ReturnsViewWithError()
        {
            TestHelpers.SeedDepartments(_context);
            var course = new Course
            {
                CourseID = 3000,
                Title = "New Course",
                Credits = 3,
                DepartmentID = 1
            };

            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns("test.exe");
            mockFile.Setup(f => f.Length).Returns(1024);

            var result = _controller.Create(course, mockFile.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_POST_FileTooLarge_ReturnsViewWithError()
        {
            TestHelpers.SeedDepartments(_context);
            var course = new Course
            {
                CourseID = 3000,
                Title = "New Course",
                Credits = 3,
                DepartmentID = 1
            };

            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns("test.jpg");
            mockFile.Setup(f => f.Length).Returns(6 * 1024 * 1024); // 6MB

            var result = _controller.Create(course, mockFile.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_POST_AllImageExtensionsAllowed()
        {
            var allowedExtensions = new[] { ".jpg", ".jpeg", ".png", ".gif", ".bmp" };

            foreach (var ext in allowedExtensions)
            {
                var context = TestHelpers.CreateContext();
                TestHelpers.SeedDepartments(context);
                var tempDir = Path.Combine(Path.GetTempPath(), "contoso_ext_test_" + Guid.NewGuid().ToString("N"));
                Directory.CreateDirectory(tempDir);

                var mockEnv = new Mock<IWebHostEnvironment>();
                mockEnv.Setup(e => e.WebRootPath).Returns(tempDir);
                var controller = new CoursesController(context, mockEnv.Object, _mockLogger.Object);
                controller.ControllerContext = new ControllerContext { HttpContext = new DefaultHttpContext() };
                controller.TempData = new TempDataDictionary(controller.ControllerContext.HttpContext, Mock.Of<ITempDataProvider>());

                var course = new Course { CourseID = 3000, Title = "Test", Credits = 3, DepartmentID = 1 };
                var mockFile = new Mock<IFormFile>();
                mockFile.Setup(f => f.FileName).Returns($"test{ext}");
                mockFile.Setup(f => f.Length).Returns(1024);
                mockFile.Setup(f => f.CopyTo(It.IsAny<Stream>()));

                var result = controller.Create(course, mockFile.Object);

                Assert.IsType<RedirectToActionResult>(result);

                controller.Dispose();
                context.Dispose();
                try { Directory.Delete(tempDir, true); } catch { }
            }
        }

        #endregion

        #region Edit GET

        [Fact]
        public void Edit_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_GET_ValidId_ReturnsViewWithCourse()
        {
            TestHelpers.SeedCourses(_context);

            var result = _controller.Edit((int?)1050) as ViewResult;

            Assert.NotNull(result);
            var course = Assert.IsType<Course>(result.Model);
            Assert.Equal("Chemistry", course.Title);
        }

        [Fact]
        public void Edit_GET_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit((int?)9999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_GET_SetsViewBagDepartmentID()
        {
            TestHelpers.SeedCourses(_context);

            _controller.Edit((int?)1050);

            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        #endregion

        #region Edit POST

        [Fact]
        public void Edit_POST_ValidModel_RedirectsToIndex()
        {
            TestHelpers.SeedCourses(_context);
            var course = new Course
            {
                CourseID = 1050,
                Title = "Updated Chemistry",
                Credits = 4,
                DepartmentID = 1
            };
            // Detach tracked entity
            var tracked = _context.ChangeTracker.Entries<Course>().FirstOrDefault(e => ((Course)e.Entity).CourseID == 1050);
            if (tracked != null) tracked.State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var result = _controller.Edit(course, null) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_POST_InvalidModelState_ReturnsView()
        {
            TestHelpers.SeedCourses(_context);
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 1050, DepartmentID = 1 };

            var result = _controller.Edit(course, null) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_POST_WithImage_InvalidExtension_ReturnsViewWithError()
        {
            TestHelpers.SeedCourses(_context);
            var course = new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 };

            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns("test.pdf");
            mockFile.Setup(f => f.Length).Returns(1024);

            var result = _controller.Edit(course, mockFile.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Edit_POST_WithImage_TooLarge_ReturnsViewWithError()
        {
            TestHelpers.SeedCourses(_context);
            var course = new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 };

            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns("test.png");
            mockFile.Setup(f => f.Length).Returns(10 * 1024 * 1024);

            var result = _controller.Edit(course, mockFile.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        #endregion

        #region Delete

        [Fact]
        public void Delete_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_GET_ValidId_ReturnsViewWithCourse()
        {
            TestHelpers.SeedCourses(_context);

            var result = _controller.Delete(1050) as ViewResult;

            Assert.NotNull(result);
            var course = Assert.IsType<Course>(result.Model);
            Assert.Equal("Chemistry", course.Title);
        }

        [Fact]
        public void Delete_GET_InvalidId_ThrowsInvalidOperationException()
        {
            Assert.Throws<InvalidOperationException>(() => _controller.Delete(9999));
        }

        [Fact]
        public void DeleteConfirmed_ValidId_RedirectsToIndex()
        {
            TestHelpers.SeedCourses(_context);

            var result = _controller.DeleteConfirmed(1050) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void DeleteConfirmed_ValidId_RemovesCourse()
        {
            TestHelpers.SeedCourses(_context);

            _controller.DeleteConfirmed(1050);

            Assert.Null(_context.Courses.Find(1050));
        }

        [Fact]
        public void DeleteConfirmed_CourseWithImage_DeletesFile()
        {
            TestHelpers.SeedCourses(_context);
            var uploadsDir = Path.Combine(_tempDir, "Uploads", "TeachingMaterials");
            Directory.CreateDirectory(uploadsDir);
            var imageFile = Path.Combine(uploadsDir, "test_image.jpg");
            File.WriteAllText(imageFile, "dummy");

            var course = _context.Courses.Find(1050);
            course.TeachingMaterialImagePath = "/Uploads/TeachingMaterials/test_image.jpg";
            _context.SaveChanges();

            _controller.DeleteConfirmed(1050);

            Assert.False(File.Exists(imageFile));
        }

        #endregion
    }
}

