using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Moq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class DepartmentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly DepartmentsController _controller;

        public DepartmentsControllerTests()
        {
            _context = TestHelpers.CreateContext();
            _controller = new DepartmentsController(_context);
            _controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
            _controller.TempData = new TempDataDictionary(
                _controller.ControllerContext.HttpContext,
                Mock.Of<ITempDataProvider>());
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        #region Index

        [Fact]
        public void Index_ReturnsViewWithDepartments()
        {
            TestHelpers.SeedDepartments(_context);

            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<List<Department>>(result.Model);
            Assert.Equal(2, model.Count);
        }

        [Fact]
        public void Index_NoDepartments_ReturnsEmptyList()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<List<Department>>(result.Model);
            Assert.Empty(model);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithDepartment()
        {
            TestHelpers.SeedDepartments(_context);

            var result = _controller.Details(1) as ViewResult;

            Assert.NotNull(result);
            var department = Assert.IsType<Department>(result.Model);
            Assert.Equal("English", department.Name);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(999);

            Assert.IsType<NotFoundResult>(result);
        }

        #endregion

        #region Create

        [Fact]
        public void Create_GET_ReturnsView()
        {
            TestHelpers.SeedInstructors(_context);

            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Create_GET_SetsViewBagInstructorID()
        {
            TestHelpers.SeedInstructors(_context);

            _controller.Create();

            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        [Fact]
        public void Create_POST_ValidModel_RedirectsToIndex()
        {
            var department = new Department
            {
                Name = "Science",
                Budget = 200000,
                StartDate = DateTime.Parse("2020-01-01")
            };

            var result = _controller.Create(department) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Create_POST_ValidModel_SavesDepartment()
        {
            var department = new Department
            {
                Name = "Science",
                Budget = 200000,
                StartDate = DateTime.Parse("2020-01-01")
            };

            _controller.Create(department);

            Assert.Single(_context.Departments);
            Assert.Equal("Science", _context.Departments.First().Name);
        }

        [Fact]
        public void Create_POST_InvalidModelState_ReturnsView()
        {
            TestHelpers.SeedInstructors(_context);
            _controller.ModelState.AddModelError("Name", "Required");
            var department = new Department { Budget = 100000 };

            var result = _controller.Create(department) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Create_POST_InvalidModelState_SetsViewBagInstructorID()
        {
            TestHelpers.SeedInstructors(_context);
            _controller.ModelState.AddModelError("Name", "Required");
            var department = new Department { Budget = 100000 };

            _controller.Create(department);

            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        #endregion

        #region Edit

        [Fact]
        public void Edit_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_GET_ValidId_ReturnsViewWithDepartment()
        {
            TestHelpers.SeedDepartments(_context);

            var result = _controller.Edit((int?)1) as ViewResult;

            Assert.NotNull(result);
            var department = Assert.IsType<Department>(result.Model);
            Assert.Equal("English", department.Name);
        }

        [Fact]
        public void Edit_GET_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit((int?)999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_GET_SetsViewBagInstructorID()
        {
            TestHelpers.SeedDepartments(_context);
            TestHelpers.SeedInstructors(_context);

            _controller.Edit((int?)1);

            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        [Fact]
        public void Edit_POST_ValidModel_RedirectsToIndex()
        {
            TestHelpers.SeedDepartments(_context);
            var department = new Department
            {
                DepartmentID = 1,
                Name = "Updated English",
                Budget = 400000,
                StartDate = DateTime.Parse("2007-09-01")
            };
            // Detach tracked entity
            var tracked = _context.ChangeTracker.Entries<Department>().FirstOrDefault(e => ((Department)e.Entity).DepartmentID == 1);
            if (tracked != null) tracked.State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var result = _controller.Edit(department) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_POST_InvalidModelState_ReturnsView()
        {
            TestHelpers.SeedDepartments(_context);
            TestHelpers.SeedInstructors(_context);
            _controller.ModelState.AddModelError("Name", "Required");
            var department = new Department { DepartmentID = 1 };

            var result = _controller.Edit(department) as ViewResult;

            Assert.NotNull(result);
        }

        #endregion

        #region Delete

        [Fact]
        public void Delete_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_GET_ValidId_ReturnsViewWithDepartment()
        {
            TestHelpers.SeedDepartments(_context);

            var result = _controller.Delete(1) as ViewResult;

            Assert.NotNull(result);
            var department = Assert.IsType<Department>(result.Model);
            Assert.Equal("English", department.Name);
        }

        [Fact]
        public void Delete_GET_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void DeleteConfirmed_ValidId_RedirectsToIndex()
        {
            TestHelpers.SeedDepartments(_context);

            var result = _controller.DeleteConfirmed(1) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void DeleteConfirmed_ValidId_RemovesDepartment()
        {
            TestHelpers.SeedDepartments(_context);

            _controller.DeleteConfirmed(1);

            Assert.Null(_context.Departments.Find(1));
            Assert.Single(_context.Departments);
        }

        #endregion
    }
}

