using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Moq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            _context = TestHelpers.CreateContext();
            _controller = new InstructorsController(_context);
            _controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
            _controller.TempData = new TempDataDictionary(
                _controller.ControllerContext.HttpContext,
                Mock.Of<ITempDataProvider>());
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        #region Index

        [Fact]
        public void Index_NoParams_ReturnsViewWithInstructors()
        {
            TestHelpers.SeedFullData(_context);

            var result = _controller.Index(null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.NotNull(model.Instructors);
            Assert.Equal(2, model.Instructors.Count());
        }

        [Fact]
        public void Index_InstructorsOrderedByLastName()
        {
            TestHelpers.SeedFullData(_context);

            var result = _controller.Index(null, null) as ViewResult;
            var model = Assert.IsType<InstructorIndexData>(result.Model);

            var instructors = model.Instructors.ToList();
            Assert.Equal("Abercrombie", instructors[0].LastName);
            Assert.Equal("Fakhouri", instructors[1].LastName);
        }

        [Fact]
        public void Index_WithInstructorId_SetsCoursesInViewModel()
        {
            TestHelpers.SeedFullData(_context);

            var result = _controller.Index(10, null) as ViewResult;
            var model = Assert.IsType<InstructorIndexData>(result.Model);

            Assert.NotNull(model.Courses);
            Assert.Single(model.Courses);
            Assert.Equal(10, _controller.ViewBag.InstructorID);
        }

        [Fact]
        public void Index_WithInstructorIdAndCourseId_SetsEnrollments()
        {
            TestHelpers.SeedFullData(_context);

            var result = _controller.Index(10, 1050) as ViewResult;
            var model = Assert.IsType<InstructorIndexData>(result.Model);

            Assert.NotNull(model.Enrollments);
            Assert.Equal(1050, _controller.ViewBag.CourseID);
        }

        [Fact]
        public void Index_NoInstructors_ReturnsEmptyViewModel()
        {
            var result = _controller.Index(null, null) as ViewResult;
            var model = Assert.IsType<InstructorIndexData>(result.Model);

            Assert.Empty(model.Instructors);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithInstructor()
        {
            TestHelpers.SeedInstructors(_context);

            var result = _controller.Details(10) as ViewResult;

            Assert.NotNull(result);
            var instructor = Assert.IsType<Instructor>(result.Model);
            Assert.Equal("Abercrombie", instructor.LastName);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(999);

            Assert.IsType<NotFoundResult>(result);
        }

        #endregion

        #region Create

        [Fact]
        public void Create_GET_ReturnsViewWithInstructor()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            var instructor = Assert.IsType<Instructor>(result.Model);
            Assert.NotNull(instructor.CourseAssignments);
            Assert.Empty(instructor.CourseAssignments);
        }

        [Fact]
        public void Create_GET_SetsViewBagCourses()
        {
            TestHelpers.SeedCourses(_context);

            _controller.Create();

            Assert.NotNull(_controller.ViewBag.Courses);
            var courses = Assert.IsAssignableFrom<List<AssignedCourseData>>(_controller.ViewBag.Courses);
            Assert.Equal(2, courses.Count);
        }

        [Fact]
        public void Create_POST_ValidModel_RedirectsToIndex()
        {
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = DateTime.Parse("2020-01-01")
            };

            var result = _controller.Create(instructor, null) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Create_POST_ValidModel_SavesInstructor()
        {
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = DateTime.Parse("2020-01-01")
            };

            _controller.Create(instructor, null);

            Assert.Single(_context.Instructors);
        }

        [Fact]
        public void Create_POST_WithSelectedCourses_AddsCourseAssignments()
        {
            TestHelpers.SeedCourses(_context);
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = DateTime.Parse("2020-01-01")
            };

            _controller.Create(instructor, new[] { "1050", "4022" });

            var saved = _context.Instructors.First();
            Assert.Equal(2, _context.CourseAssignments.Count(ca => ca.InstructorID == saved.ID));
        }

        [Fact]
        public void Create_POST_InvalidModelState_ReturnsView()
        {
            TestHelpers.SeedCourses(_context);
            _controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor
            {
                FirstMidName = "New",
                HireDate = DateTime.Parse("2020-01-01")
            };

            var result = _controller.Create(instructor, null) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Create_POST_InvalidModelState_SetsViewBagCourses()
        {
            TestHelpers.SeedCourses(_context);
            _controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor
            {
                FirstMidName = "New",
                HireDate = DateTime.Parse("2020-01-01"),
                CourseAssignments = new List<CourseAssignment>()
            };

            _controller.Create(instructor, null);

            Assert.NotNull(_controller.ViewBag.Courses);
        }

        #endregion

        #region Edit GET

        [Fact]
        public void Edit_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_GET_ValidId_ReturnsViewWithInstructor()
        {
            TestHelpers.SeedFullData(_context);

            var result = _controller.Edit((int?)10) as ViewResult;

            Assert.NotNull(result);
            var instructor = Assert.IsType<Instructor>(result.Model);
            Assert.Equal("Abercrombie", instructor.LastName);
        }

        [Fact]
        public void Edit_GET_SetsViewBagCourses()
        {
            TestHelpers.SeedFullData(_context);

            _controller.Edit((int?)10);

            Assert.NotNull(_controller.ViewBag.Courses);
            var courses = Assert.IsAssignableFrom<List<AssignedCourseData>>(_controller.ViewBag.Courses);
            Assert.NotEmpty(courses);
        }

        [Fact]
        public void Edit_GET_PopulatesAssignedCourses()
        {
            TestHelpers.SeedFullData(_context);

            _controller.Edit((int?)10);

            var courses = Assert.IsAssignableFrom<List<AssignedCourseData>>(_controller.ViewBag.Courses);
            var assignedCourse = courses.FirstOrDefault(c => c.CourseID == 1050);
            Assert.NotNull(assignedCourse);
            Assert.True(assignedCourse.Assigned);
        }

        [Fact]
        public void Edit_GET_MarksUnassignedCourses()
        {
            TestHelpers.SeedFullData(_context);

            _controller.Edit((int?)10);

            var courses = Assert.IsAssignableFrom<List<AssignedCourseData>>(_controller.ViewBag.Courses);
            var unassignedCourse = courses.FirstOrDefault(c => c.CourseID == 4022);
            Assert.NotNull(unassignedCourse);
            Assert.False(unassignedCourse.Assigned);
        }

        #endregion

        #region Delete

        [Fact]
        public void Delete_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_GET_ValidId_ReturnsViewWithInstructor()
        {
            TestHelpers.SeedInstructors(_context);

            var result = _controller.Delete(10) as ViewResult;

            Assert.NotNull(result);
            var instructor = Assert.IsType<Instructor>(result.Model);
            Assert.Equal("Abercrombie", instructor.LastName);
        }

        [Fact]
        public void Delete_GET_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void DeleteConfirmed_ValidId_RedirectsToIndex()
        {
            TestHelpers.SeedFullData(_context);

            var result = _controller.DeleteConfirmed(10) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void DeleteConfirmed_ValidId_RemovesInstructor()
        {
            TestHelpers.SeedFullData(_context);

            _controller.DeleteConfirmed(10);

            Assert.Null(_context.Instructors.Find(10));
        }

        [Fact]
        public void DeleteConfirmed_InstructorIsDepartmentAdmin_ClearsDepartmentAdmin()
        {
            TestHelpers.SeedFullData(_context);
            // Set instructor 10 as department admin
            var dept = _context.Departments.First();
            dept.InstructorID = 10;
            _context.SaveChanges();

            _controller.DeleteConfirmed(10);

            var updatedDept = _context.Departments.Find(dept.DepartmentID);
            Assert.Null(updatedDept.InstructorID);
        }

        [Fact]
        public void DeleteConfirmed_InstructorNotDepartmentAdmin_DoesNotAffectDepartments()
        {
            TestHelpers.SeedFullData(_context);
            // Ensure instructor 11 is not an admin
            foreach (var dept in _context.Departments)
            {
                if (dept.InstructorID == 11) dept.InstructorID = null;
            }
            _context.SaveChanges();

            _controller.DeleteConfirmed(11);

            // Departments remain unchanged
            Assert.True(_context.Departments.Any());
        }

        #endregion
    }
}

