using Xunit;

namespace ContosoUniversity.Tests.Data
{
    public class DbInitializerTests
    {
        [Fact]
        public void Initialize_EmptyDatabase_SeedsData()
        {
            using var context = TestHelpers.CreateContext();

            DbInitializer.Initialize(context);

            Assert.True(context.Students.Any());
            Assert.True(context.Instructors.Any());
            Assert.True(context.Departments.Any());
            Assert.True(context.Courses.Any());
            Assert.True(context.Enrollments.Any());
            Assert.True(context.CourseAssignments.Any());
            Assert.True(context.OfficeAssignments.Any());
        }

        [Fact]
        public void Initialize_SeedsCorrectNumberOfStudents()
        {
            using var context = TestHelpers.CreateContext();

            DbInitializer.Initialize(context);

            Assert.Equal(8, context.Students.Count());
        }

        [Fact]
        public void Initialize_SeedsCorrectNumberOfInstructors()
        {
            using var context = TestHelpers.CreateContext();

            DbInitializer.Initialize(context);

            Assert.Equal(5, context.Instructors.Count());
        }

        [Fact]
        public void Initialize_SeedsCorrectNumberOfDepartments()
        {
            using var context = TestHelpers.CreateContext();

            DbInitializer.Initialize(context);

            Assert.Equal(4, context.Departments.Count());
        }

        [Fact]
        public void Initialize_SeedsCorrectNumberOfCourses()
        {
            using var context = TestHelpers.CreateContext();

            DbInitializer.Initialize(context);

            Assert.Equal(7, context.Courses.Count());
        }

        [Fact]
        public void Initialize_AlreadySeeded_DoesNotDuplicate()
        {
            using var context = TestHelpers.CreateContext();

            DbInitializer.Initialize(context);
            var studentCount = context.Students.Count();

            DbInitializer.Initialize(context);

            Assert.Equal(studentCount, context.Students.Count());
        }

        [Fact]
        public void Initialize_SeedsStudentNames()
        {
            using var context = TestHelpers.CreateContext();

            DbInitializer.Initialize(context);

            Assert.Contains(context.Students, s => s.LastName == "Alexander");
            Assert.Contains(context.Students, s => s.LastName == "Alonso");
            Assert.Contains(context.Students, s => s.LastName == "Anand");
        }

        [Fact]
        public void Initialize_SeedsDepartmentNames()
        {
            using var context = TestHelpers.CreateContext();

            DbInitializer.Initialize(context);

            Assert.Contains(context.Departments, d => d.Name == "English");
            Assert.Contains(context.Departments, d => d.Name == "Mathematics");
            Assert.Contains(context.Departments, d => d.Name == "Engineering");
            Assert.Contains(context.Departments, d => d.Name == "Economics");
        }

        [Fact]
        public void Initialize_SeedsCourseIds()
        {
            using var context = TestHelpers.CreateContext();

            DbInitializer.Initialize(context);

            Assert.NotNull(context.Courses.Find(1050));
            Assert.NotNull(context.Courses.Find(4022));
            Assert.NotNull(context.Courses.Find(1045));
        }

        [Fact]
        public void Initialize_SeedsOfficeAssignments()
        {
            using var context = TestHelpers.CreateContext();

            DbInitializer.Initialize(context);

            Assert.Equal(3, context.OfficeAssignments.Count());
        }

        [Fact]
        public void Initialize_SeedsEnrollmentsWithGrades()
        {
            using var context = TestHelpers.CreateContext();

            DbInitializer.Initialize(context);

            Assert.Contains(context.Enrollments, e => e.Grade == Grade.A);
            Assert.Contains(context.Enrollments, e => e.Grade == Grade.B);
            Assert.Contains(context.Enrollments, e => e.Grade == Grade.C);
            Assert.Contains(context.Enrollments, e => e.Grade == null);
        }

        [Fact]
        public void Initialize_SeedsDepartmentsWithAdministrators()
        {
            using var context = TestHelpers.CreateContext();

            DbInitializer.Initialize(context);

            Assert.All(context.Departments, d => Assert.NotNull(d.InstructorID));
        }
    }
}

