using System;
using System.Linq;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.EntityFrameworkCore;
using Xunit;

namespace ContosoUniversity.Tests.Data
{
    public class SchoolContextTests
    {
        [Fact]
        public void CanCreateContext()
        {
            using var context = TestHelpers.CreateContext();
            Assert.NotNull(context);
        }

        [Fact]
        public void CanAddAndRetrieveStudent()
        {
            using var context = TestHelpers.CreateContext();
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.Parse("2020-09-01")
            };

            context.Students.Add(student);
            context.SaveChanges();

            Assert.Single(context.Students);
            Assert.Equal("Test", context.Students.First().FirstMidName);
        }

        [Fact]
        public void CanAddAndRetrieveInstructor()
        {
            using var context = TestHelpers.CreateContext();
            var instructor = new Instructor
            {
                FirstMidName = "Kim",
                LastName = "Abercrombie",
                HireDate = DateTime.Parse("1995-03-11")
            };

            context.Instructors.Add(instructor);
            context.SaveChanges();

            Assert.Single(context.Instructors);
        }

        [Fact]
        public void CanAddAndRetrieveDepartment()
        {
            using var context = TestHelpers.CreateContext();
            var dept = new Department
            {
                Name = "Test Dept",
                Budget = 100000,
                StartDate = DateTime.Now
            };

            context.Departments.Add(dept);
            context.SaveChanges();

            Assert.Single(context.Departments);
        }

        [Fact]
        public void CanAddAndRetrieveCourse()
        {
            using var context = TestHelpers.CreateContext();
            var dept = new Department { Name = "Test", Budget = 100000, StartDate = DateTime.Now };
            context.Departments.Add(dept);
            context.SaveChanges();

            var course = new Course { CourseID = 1000, Title = "Test", Credits = 3, DepartmentID = dept.DepartmentID };
            context.Courses.Add(course);
            context.SaveChanges();

            Assert.Single(context.Courses);
        }

        [Fact]
        public void CourseAssignment_HasCompositeKey()
        {
            using var context = TestHelpers.CreateContext();
            TestHelpers.SeedFullData(context);

            var ca = context.CourseAssignments.FirstOrDefault();
            Assert.NotNull(ca);
        }

        [Fact]
        public void CanAddNotification()
        {
            using var context = TestHelpers.CreateContext();
            var notification = new Notification
            {
                EntityType = "Student",
                EntityId = "1",
                Operation = "CREATE",
                Message = "Test",
                CreatedAt = DateTime.Now,
                CreatedBy = "System",
                IsRead = false
            };

            context.Notifications.Add(notification);
            context.SaveChanges();

            Assert.Single(context.Notifications);
        }

        [Fact]
        public void CanAddEnrollment()
        {
            using var context = TestHelpers.CreateContext();
            TestHelpers.SeedStudents(context);
            TestHelpers.SeedCourses(context);

            var enrollment = new Enrollment
            {
                StudentID = 1,
                CourseID = 1050,
                Grade = Grade.A
            };

            context.Enrollments.Add(enrollment);
            context.SaveChanges();

            Assert.Single(context.Enrollments);
        }

        [Fact]
        public void CanAddOfficeAssignment()
        {
            using var context = TestHelpers.CreateContext();
            TestHelpers.SeedInstructors(context);

            var office = new OfficeAssignment
            {
                InstructorID = 10,
                Location = "Room 101"
            };

            context.OfficeAssignments.Add(office);
            context.SaveChanges();

            Assert.Single(context.OfficeAssignments);
        }

        [Fact]
        public void StudentsAndInstructorsSharePersonTable()
        {
            using var context = TestHelpers.CreateContext();
            context.Students.Add(new Student { FirstMidName = "S", LastName = "Student", EnrollmentDate = DateTime.Now });
            context.Instructors.Add(new Instructor { FirstMidName = "I", LastName = "Instructor", HireDate = DateTime.Now });
            context.SaveChanges();

            // Both should appear in People (TPH)
            Assert.Equal(2, context.People.Count());
        }
    }
}

