using System;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Moq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class NotificationsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly NotificationsController _controller;

        public NotificationsControllerTests()
        {
            _context = TestHelpers.CreateContext();
            _controller = new NotificationsController(_context);
            _controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
            _controller.TempData = new TempDataDictionary(
                _controller.ControllerContext.HttpContext,
                Mock.Of<ITempDataProvider>());
            // Drain any existing notifications
            TestHelpers.DrainNotificationQueue(_controller.notificationService);
        }

        public void Dispose()
        {
            TestHelpers.DrainNotificationQueue(_controller.notificationService);
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void GetNotifications_EmptyQueue_ReturnsEmptyList()
        {
            var result = _controller.GetNotifications();

            Assert.NotNull(result);
            // The result has success=true and count=0
            var json = result.Value;
            Assert.NotNull(json);
        }

        [Fact]
        public void GetNotifications_WithNotifications_ReturnsNotifications()
        {
            // Send some notifications through the service
            _controller.notificationService.SendNotification("Student", "1", "John", EntityOperation.CREATE);
            _controller.notificationService.SendNotification("Course", "2", "Math", EntityOperation.UPDATE);

            var result = _controller.GetNotifications();

            Assert.NotNull(result);
            Assert.NotNull(result.Value);
        }

        [Fact]
        public void GetNotifications_LimitsTo10()
        {
            // Send more than 10 notifications
            for (int i = 0; i < 15; i++)
            {
                _controller.notificationService.SendNotification("Student", i.ToString(), EntityOperation.CREATE);
            }

            var result = _controller.GetNotifications();

            Assert.NotNull(result);
        }

        [Fact]
        public void MarkAsRead_ReturnsJsonResult()
        {
            var result = _controller.MarkAsRead(1);

            Assert.NotNull(result);
            Assert.IsType<JsonResult>(result);
        }

        [Fact]
        public void MarkAsRead_WithAnyId_ReturnsSuccess()
        {
            var result = _controller.MarkAsRead(999);

            Assert.NotNull(result);
        }

        [Fact]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index();

            Assert.IsType<ViewResult>(result);
        }
    }
}

