[Fact]
public void SendNotification_SetsCreatedAt()
{
    var before = DateTime.Now;
    _service.SendNotification("Student", "1", EntityOperation.CREATE);
    var after = DateTime.Now;

    var notification = _service.ReceiveNotification();
    Assert.InRange(notification.CreatedAt, before, after);
}

toolArgs.new_str:
[Fact]
public void SendNotification_SetsCreatedAt()
{
    var before = DateTime.Now.AddSeconds(-1);
    _service.SendNotification("Student", "1", "Test", EntityOperation.CREATE, "testuser");
    var after = DateTime.Now.AddSeconds(1);

    // Drain until we find the one we sent
    Notification notification = null;
    Notification candidate;
    while ((candidate = _service.ReceiveNotification()) != null)
    {
        if (candidate.EntityType == "Student" && candidate.EntityId == "1" && candidate.CreatedBy == "testuser")
        {
            notification = candidate;
            break;
        }
    }
    Assert.NotNull(notification);
    Assert.InRange(notification.CreatedAt, before, after);
}

